const token = env.get("ORCE_ARCHIVE_AUDIT_LOG_BEARER_TOKEN");
if (!token || msg.req?.headers?.authorization !== `Bearer ${token}`) { msg.statusCode = 401; msg.payload = {error: "Unauthorized"}; return msg; }
