for (const key of required) { if (!msg.payload || msg.payload[key] === undefined || msg.payload[key] === null || msg.payload[key] === "") { msg.statusCode = 400; msg.payload = {error: `Missing field: ${key}`}; return msg; } }
const path = "/data/archive-audit-events.jsonl";
