try { events = fs.readFileSync(path, "utf8").split(/\r?\n/).filter(Boolean).map(JSON.parse); } catch (error) { if (error.code !== "ENOENT") { msg.statusCode = 500; msg.payload = {error: "Cannot read archive chain"}; return msg; } }
let head = null;
for (const event of events) { const {eventHash, ...payload} = event; const expected = "sha256:" + crypto.createHash("sha256").update(JSON.stringify(payload)).digest("hex"); if (event.previousHash !== head || eventHash !== expected) { msg.statusCode = 409; msg.payload = {error: "Persistent archive chain is invalid"}; return msg; } head = eventHash; }
