if (existing) { const same = required.every(key => existing[key] === input[key]); if (!same) { msg.statusCode = 409; msg.payload = {error: "Archive entry id already exists with different content"}; return msg; } msg.receipt = {receiptType: "ARCHIVE_NOTARY_RECEIPT", archiveEntryId: existing.archiveEntryId, eventHash: existing.eventHash, previousHash: existing.previousHash, receivedAt: existing.receivedAt}; return msg; }
const auditPayload = {...input, receivedAt: new Date().toISOString(), previousHash: head};
const eventHash = "sha256:" + crypto.createHash("sha256").update(JSON.stringify(auditPayload)).digest("hex");
const storedEvent = {...auditPayload, eventHash};
fs.appendFileSync(path, JSON.stringify(storedEvent) + "\n", {encoding: "utf8"});
msg.receipt = {receiptType: "ARCHIVE_NOTARY_RECEIPT", archiveEntryId: storedEvent.archiveEntryId, eventHash, previousHash: head, receivedAt: storedEvent.receivedAt};
return msg;

msg.headers = {"Content-Type": "application/json"};
if (msg.receipt) { msg.statusCode = 200; msg.payload = msg.receipt; }
return msg;

const configuredToken = env.get("ORCE_ARCHIVE_AUDIT_LOG_BEARER_TOKEN");
const expected = configuredToken ? `Bearer ${configuredToken}` : null;
const actual = msg.req?.headers?.authorization;

